/**
 * Resolve a user-supplied value to a numeric index in the named enum.
 * Accepts numeric input directly, exact name match, and a relaxed
 * case-insensitive match after collapsing non-alphanumerics — so
 * "Lo-Fi", "lofi", "lo fi", and 5 all resolve the same FX_TYPES entry.
 * Returns undefined if the input is unknown or the enum does not exist.
 */
export function resolveHydraEnum(enumName: string, input: number | string): number | undefined {
  const table = HYDRASYNTH_ENUMS[enumName];
  if (!table) return undefined;
  if (typeof input === 'number') {
    return table[input] !== undefined ? input : undefined;
  }
  const trimmed = input.trim();
  if (trimmed === '') return undefined;
  for (const [idx, name] of Object.entries(table)) {
    if (name === trimmed) return Number(idx);
  }
  const normalize = (s: string) => s.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
  const target = normalize(trimmed);
  for (const [idx, name] of Object.entries(table)) {
    if (normalize(name) === target) return Number(idx);
  }
  // Substring fallback: unique partial match on either side.
  const hits: number[] = [];
  for (const [idx, name] of Object.entries(table)) {
    const n = normalize(name);
    if (n.includes(target) || target.includes(n)) hits.push(Number(idx));
  }
  return hits.length === 1 ? hits[0] : undefined;
}
